// Calculate velocity multipliers and upsert baselines
const userId = $('Loop Users').first().json.user_id;
const velocityRows = $input.all();
const upserts = [];
const logEntries = [];

for (const row of velocityRows) {
  const v = row.json;
  const weeks = parseInt(v.weeks_tracked) || 0;
  const avg = parseFloat(v.avg_signals_per_week) || 0;
  const stddev = parseFloat(v.stddev_signals_per_week) || 1;

  // Only calibrate after 8+ weeks of data
  let multiplier = 1.0;
  if (weeks >= 8) {
    // Get this week's count (most recent week)
    // For now, use avg as proxy — the actual deviation
    // will be computed when we have this week's fresh data
    // The key insight: we store the baseline and the pipeline
    // uses it to boost/dampen scores at scoring time
    multiplier = 1.0; // Will be updated by the scoring pipeline
  }

  upserts.push({
    user_id: userId,
    company_id: v.company_id,
    company_name: v.company_name,
    signal_type: v.signal_type,
    weeks_tracked: weeks,
    avg_signals_per_week: avg,
    stddev_signals_per_week: stddev,
    last_signal_at: v.last_signal_at,
    velocity_multiplier: multiplier,
  });
}

if (upserts.length === 0) {
  return [{ json: { user_id: userId, velocity_count: 0, message: 'No velocity data' } }];
}

return [{ json: { user_id: userId, velocity_upserts: upserts, velocity_count: upserts.length } }];

