// Calculate prediction calibration and upsert
const userId = $('Loop Users').first().json.user_id;
const predRows = $input.all();
const upserts = [];

for (const row of predRows) {
  const p = row.json;
  const total = parseInt(p.total_predictions) || 0;
  const correct = parseInt(p.correct_count) || 0;
  const partial = parseInt(p.partial_count) || 0;
  const incorrect = parseInt(p.incorrect_count) || 0;
  const accuracy = parseFloat(p.accuracy_rate) || 0;

  // Confidence adjustment: positive if accuracy > 70%, negative if < 50%
  let confidenceAdj = 0;
  if (total >= 8) {
    if (accuracy >= 80) confidenceAdj = 5;
    else if (accuracy >= 70) confidenceAdj = 2;
    else if (accuracy < 40) confidenceAdj = -5;
    else if (accuracy < 50) confidenceAdj = -2;
  }

  // Predictability score: how consistent the accuracy is
  const predictability = total >= 8 ? Math.min(1, accuracy / 100) : null;

  upserts.push({
    user_id: userId,
    company_id: p.company_id,
    company_name: p.company_name,
    total_predictions: total,
    correct_count: correct,
    partial_count: partial,
    incorrect_count: incorrect,
    accuracy_rate: accuracy,
    confidence_adjustment: confidenceAdj,
    predictability_score: predictability,
    is_calibrated: total >= 8,
  });
}

if (upserts.length === 0) {
  return [{ json: { user_id: userId, prediction_count: 0, message: 'No prediction data' } }];
}

return [{ json: { user_id: userId, prediction_upserts: upserts, prediction_count: upserts.length } }];

