// Upsert severity baselines and log calibration
const userId = $('Loop Users').first().json.user_id;
const severityRows = $input.all();
const velocityCount = $('Calculate Velocity Baselines').first().json.velocity_count || 0;
const predCount = $('Calculate Prediction Calibration').first().json.prediction_count || 0;

const severityUpserts = severityRows.map(row => {
  const s = row.json;
  return {
    user_id: userId,
    signal_type: s.signal_type,
    total_signals: parseInt(s.total_signals) || 0,
    severity_p25: parseFloat(s.severity_p25),
    severity_p50: parseFloat(s.severity_p50),
    severity_p75: parseFloat(s.severity_p75),
    severity_p90: parseFloat(s.severity_p90),
    is_calibrated: (parseInt(s.total_signals) || 0) >= 50,
  };
});

// Summary
return [{ json: {
  user_id: userId,
  velocity_baselines: velocityCount,
  prediction_calibrations: predCount,
  severity_baselines: severityUpserts.length,
  severity_upserts: severityUpserts,
  status: 'calibration_complete'
} }];

