(function() {
  const data = $json;
  const parts = [];

  // Upsert severity baselines
  if (data.severity_upserts && data.severity_upserts.length > 0) {
    const values = data.severity_upserts.map(u =>
      `('${u.user_id}', '${u.signal_type}', ${u.total_signals}, ${u.severity_p25}, ${u.severity_p50}, ${u.severity_p75}, ${u.severity_p90}, ${u.is_calibrated})`
    ).join(',\n');

    parts.push(`INSERT INTO learning.market_severity_baselines (user_id, signal_type, total_signals, severity_p25, severity_p50, severity_p75, severity_p90, is_calibrated)
VALUES ${values}
ON CONFLICT (user_id, signal_type)
DO UPDATE SET
  total_signals = EXCLUDED.total_signals,
  severity_p25 = EXCLUDED.severity_p25,
  severity_p50 = EXCLUDED.severity_p50,
  severity_p75 = EXCLUDED.severity_p75,
  severity_p90 = EXCLUDED.severity_p90,
  is_calibrated = EXCLUDED.is_calibrated,
  calibration_version = learning.market_severity_baselines.calibration_version + 1,
  calibrated_at = NOW(),
  updated_at = NOW()`);
  }

  // Log the calibration run
  parts.push(`INSERT INTO learning.calibration_log (user_id, calibration_type, target_key, previous_value, new_value, data_points_used)
  VALUES ('${data.user_id}', 'weekly_run', 'all', '{"run": "previous"}', '{"velocity": ${data.velocity_baselines}, "predictions": ${data.prediction_calibrations}, "severity": ${data.severity_baselines}}', ${data.velocity_baselines + data.prediction_calibrations + data.severity_baselines})`);

  return parts.join(';\n') + ';';
})()
}}

